// Combined store for backward compatibility
import { useAuthStore } from './auth.store';
import { useProfilesStore } from './profiles.store';
import { useBusinessStore } from './business.store';
import { useAttendeesStore } from './attendees.store';
import { initialStateData } from './helpers';
import { ProfileResult, PublicProfileResult } from '@/types/profile.types';
import { BusinessResult } from '@/types/business.types';
import { AttendeeRawData, AttendeeBasicInfo } from '@/types/attendee.types';
import { TotpSetup } from '@/types/auth.types';

// Legacy combined store hook for backward compatibility
export const useStore = () => {
    const auth = useAuthStore();
    const profiles = useProfilesStore();
    const business = useBusinessStore();
    const attendees = useAttendeesStore();

    return {
        // Auth state
        ...auth,
        
        // Profile state  
        ...profiles,
        
        // Business state
        ...business,
        
        // Attendee state
        ...attendees,
    };
};

// Reset all stores function
export const ResetAllStores = () => {
    useAuthStore.setState(() => ({
        totpSetupState: initialStateData<TotpSetup>(),
    }));
    
    useProfilesStore.setState(() => ({
        profileState: initialStateData<ProfileResult>(),
        publicProfileState: initialStateData<PublicProfileResult>(),
        nearbyProfileListState: initialStateData([] as PublicProfileResult[]),
    }));
    
    useBusinessStore.setState(() => ({
        businessState: initialStateData<BusinessResult>(),
        businessStateList: initialStateData([] as BusinessResult[]),
    }));
    
    useAttendeesStore.setState(() => ({
        attendeeRawStateList: initialStateData([] as AttendeeRawData[]),
        attendeeListState: initialStateData([] as AttendeeBasicInfo[]),
    }));
};

// Default export for backward compatibility
export default useStore;
