import { CallStatus } from "@/types/api.types";
import { StateData, StateDataPage } from "./types";

export const initialStateData = <T>(data?: T): StateData<T> => ({
    data: (data ?? {}) as T,
    status: CallStatus.NotStarted,
    httpStatus: 0,
    timestamp: new Date(),
});

export const initialStateDataPage = <T>(data?: T): StateDataPage<T> => ({
    data: (data ?? {}) as T,
    page: 0,
    isLastPage: false,
    status: CallStatus.NotStarted,
    httpStatus: 0,
    timestamp: new Date(),
});
