import { create } from 'zustand';
import { StateData } from './types';
import { initialStateData } from './helpers';
import { TotpSetup } from '@/types/auth.types';

type AuthState = {
    totpSetupState: StateData<TotpSetup>;
    setTotpSetupState: (state: StateData<TotpSetup>) => void;
}

export const useAuthStore = create<AuthState>()((set) => ({
    totpSetupState: initialStateData<TotpSetup>(),
    setTotpSetupState: (state: StateData<TotpSetup>) => set(() => ({ totpSetupState: state })),
}));
