import { create } from 'zustand';
import { StateData } from './types';
import { initialStateData } from './helpers';
import { AttendeeRawData, AttendeeBasicInfo } from '@/types/attendee.types';

type AttendeesState = {
    attendeeRawStateList: StateData<AttendeeRawData[]>;
    setAttendeeRawStateList: (state: StateData<AttendeeRawData[]>) => void;
    attendeeListState: StateData<AttendeeBasicInfo[]>;
    setAttendeeListState: (state: StateData<AttendeeBasicInfo[]>) => void;
}

export const useAttendeesStore = create<AttendeesState>()((set) => ({
    attendeeRawStateList: initialStateData([] as AttendeeRawData[]),
    setAttendeeRawStateList: (state: StateData<AttendeeRawData[]>) => set(() => ({ attendeeRawStateList: state })),
    attendeeListState: initialStateData([] as AttendeeBasicInfo[]),
    setAttendeeListState: (state: StateData<AttendeeBasicInfo[]>) => set(() => ({ attendeeListState: state })),
}));
